VALUES
  ('dietitian-moex-04784', 'dietitian', 'dietitian-moex-111-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '第八版國人膳食營養素參考攝取量（DRIs）之修訂原則，下列何者正確？', '["熱量建議依身體活動分「稍低」與「適度」二級", "調降12歲以前的鐵上限攝取量（UL）至35mg", "嬰兒年齡分層為0～6個月與7～12個月", "增列維生素D建議量"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "6f5613a1a37b", "answer_pdf_sha1": "0e1aec66d21a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04785', 'dietitian', 'dietitian-moex-111-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '有關包裝食品營養宣稱應遵行事項之敘述，下列何者正確？', '["品名為「乳酸菌糖果」或「乳酸菌球飲料」，是營養宣稱的範圍", "品名為「OO維生素C飲料」，得在營養標示欄位內標示維生素C含量", "對產品原料成分敘述有「維生素A」、「維生素B」，是屬於營養宣稱 2", "捕撈之深海魚類包裝食品，可在產品包裝上宣稱「富含DHA與蛋白質」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "6f5613a1a37b", "answer_pdf_sha1": "0e1aec66d21a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04786', 'dietitian', 'dietitian-moex-111-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '依據校園飲品及點心販售規範，下列何種飲品及點心無法於高級中等以下學校販售？', '["每份所提供的脂肪占總熱量35%的全脂鮮奶", "每份添加糖占總熱量超過10%的優酪乳", "每份含有0.5公克反式脂肪的餅乾", "每份鈉含量300毫克的麵包"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "6f5613a1a37b", "answer_pdf_sha1": "0e1aec66d21a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04787', 'dietitian', 'dietitian-moex-111-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '有關嬰兒副食品的添加，下列敘述何者正確？', '["純母乳哺育者，嬰兒6個月後必須添加副食品，避免營養不良", "以母乳替代品（配方奶）哺育者，嬰兒3個月後必須添加副食品，避免營養不良", "添加副食品宜循序漸進，可由不易引起過敏的蛋類開始", "為增加嬰兒對於副食品的適應性，可酌量用鹽、糖調味"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "6f5613a1a37b", "answer_pdf_sha1": "0e1aec66d21a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04788', 'dietitian', 'dietitian-moex-111-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '有關長者健康整合式評估（IntegratedCareforOlderPeople,ICOPE），下列敘述何者錯誤？', '["世界衛生組織在民國108年所公布的ICOPE照護指南，希望早期發現長者功能衰退，以延緩衰 弱與失能，維持及改善老年人身體功能與心理健康", "依據衛生福利部國民健康署民國108年「長者衰弱評估」篩檢結果，85歲以上長者每4人有1 人可能衰弱", "ICOPE含生理功能、行動能力、營養、視力、聽力、憂鬱等6大項目", "能否在12秒內，雙手抱胸連續起立坐下5次；過去3個月體重是否突然減少3公斤以上；過 去2週是否覺得心情低落沮喪、沒有希望等，都是ICOPE評估的內容"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "6f5613a1a37b", "answer_pdf_sha1": "0e1aec66d21a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04789', 'dietitian', 'dietitian-moex-111-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '依據國際母乳代用品銷售守則（Internationalcodemarketingofbreast-milksubstitutes）建議，醫護 人員可接受配方奶公司所提供的下列那種物品？', '["嬰兒餵食指南的資料", "母乳哺育的衛教資料", "免費嬰兒毛巾或浴巾", "跟配方奶有關的科學實證資訊"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "6f5613a1a37b", "answer_pdf_sha1": "0e1aec66d21a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04790', 'dietitian', 'dietitian-moex-111-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '世界衛生組織於2021年修訂之評估「嬰幼兒餵食指標（Indicatorsforinfantandyoungchildfeeding practices）」不包括下列何項？', '["6到8個月大嬰幼兒開始餵食副食品的比例", "6到23個月大嬰幼兒最低用餐頻率", "6到23個月大嬰幼兒攝取含鐵或富含鐵質食物的比例", "6到23個月大嬰幼兒攝取含糖飲料的比例"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "6f5613a1a37b", "answer_pdf_sha1": "0e1aec66d21a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04791', 'dietitian', 'dietitian-moex-111-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '針對美國老人的營養主動檢查計畫（Nutritionscreeninginititive,NSI），下列何者不是DETERMINE 檢核表的項目？', '["抽菸、喝酒", "飲食貧乏、不自主體重減輕或增加", "疾病、缺牙、口腔疼痛、多重用藥", "經濟困難、缺乏社交互動、需要照顧協助、高齡者"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "6f5613a1a37b", "answer_pdf_sha1": "0e1aec66d21a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04792', 'dietitian', 'dietitian-moex-111-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '有關包裝食品營養標示應遵行事項之敘述，下列何者正確？', '["市售經保鮮膜包裝之滷味豆干，須營養標示", "營養標示中，孕乳婦每日熱量攝取參考值為2000大卡", "包裝維生素礦物質類之錠狀、膠囊狀食品，不適用本規定", "營養標示中的反式脂肪，係指食用油經部分氫化過程所形成的非共軛式反式脂肪酸"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "6f5613a1a37b", "answer_pdf_sha1": "0e1aec66d21a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-04793', 'dietitian', 'dietitian-moex-111-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '某病人生化檢驗後發現「前白蛋白偏低、白蛋白正常」，此病人目前之營養狀況為何？', '["嚴重營養不良，需積極營養介入", "早期營養不良，需適當飲食治療", "營養狀況已獲改善，逐漸恢復正常", "營養狀況良好，不需任何營養介入"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:37+00:00", "source_pdf_sha1": "6f5613a1a37b", "answer_pdf_sha1": "0e1aec66d21a", "source_family": "moex-gov-tw", "moex": {"exam_code": "111110", "c": "103", "s": "0205", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公共衛生營養學", "year": "111", "exam_name": "111年第二次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試、111年專技人員高等考試法醫師、語言治療師、聽力師、牙體...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
